 38→func WithPromptTimeout(d time.Duration) Option {
 39→	return func(c *runConfig) { c.PromptTimeout = d }
 40→}
 41→
 42→// Agent defines the interface for an AI coding agent that can be tested.
 43→type Agent interface {
 44→	Name() string
 45→	// Binary returns the CLI binary name (e.g. "kiro-cli-chat").
 46→	Binary() string
 47→	EntireAgent() string
 48→	PromptPattern() string
 49→	// TimeoutMultiplier returns a factor applied to per-test timeouts.
 50→	// Slower agents return values > 1.
 51→	TimeoutMultiplier() float64
 52→	RunPrompt(ctx context.Context, dir string, prompt string, opts ...Option) (Output, error)
 53→	StartSession(ctx context.Context, dir string) (Session, error)
 54→	// Bootstrap performs one-time CI setup (auth config, warmup, etc.).
 55→	// Called before any tests run. Implementations should be idempotent.
 56→	Bootstrap() error
 57→	// IsTransientError returns true if the error from RunPrompt looks like
 58→	// a transient API failure (e.g. 500, rate limit, network error) that
 59→	// is worth retrying.
 60→	IsTransientError(out Output, err error) bool
 61→}
 62→
 63→// Session represents an interactive terminal session with an agent.
 64→type Session interface {
 65→	Send(input string) error
 66→	WaitFor(pattern string, timeout time.Duration) (string, error)
 67→	Capture() string
 68→	Close() error
 69→}
 70→
 71→// ExternalAgent is an optional interface for agents discovered via the
 72→// external agent protocol (entire-agent-* binaries). SetupRepo uses this
 73→// to pre-configure external_agents in settings before running `entire enable`.
 74→type ExternalAgent interface {
 75→	IsExternalAgent() bool
 76→}
 77→
 78→// registry and gates are populated by init() functions in agent implementation
 79→// files (e.g. kiro.go). Go guarantees init() functions run sequentially, so
 80→// no synchronization is needed. Do not call Register/RegisterGate from tests.
 81→var registry []Agent
 82→var gates = map[string]chan struct{}{}
 83→
 84→// Register adds an agent to the global registry.
 85→func Register(a Agent) {
 86→	registry = append(registry, a)
 87→}
 88→
 89→// RegisterGate sets a concurrency limit for an agent's tests.
 90→// Tests call AcquireSlot/ReleaseSlot to respect this limit.
 91→// The limit can be overridden via E2E_CONCURRENT_TEST_LIMIT.
 92→func RegisterGate(name string, defaultMax int) {
 93→	max := defaultMax
 94→	if v, err := strconv.Atoi(os.Getenv("E2E_CONCURRENT_TEST_LIMIT")); err == nil && v > 0 {
 95→		max = v
 96→	}
 97→	gates[name] = make(chan struct{}, max)
 98→}
 99→
100→// AcquireSlot blocks until a test slot is available for the agent or the
101→// context is cancelled. Returns a non-nil error if the context expires
102→// before a slot opens.
103→func AcquireSlot(ctx context.Context, a Agent) error {
104→	g, ok := gates[a.Name()]
105→	if !ok {
106→		return nil
107→	}
108→	select {
109→	case g <- struct{}{}:
110→		return nil
111→	case <-ctx.Done():
112→		return ctx.Err()
113→	}
114→}
115→
116→// ReleaseSlot frees a test slot for the agent.
117→func ReleaseSlot(a Agent) {
118→	if g, ok := gates[a.Name()]; ok {
119→		<-g
120→	}
121→}
122→
123→// All returns all registered agents.
124→func All() []Agent {
125→	return registry
126→}
127→
128→// filterEnv returns env with entries matching any of the given variable names
129→// removed. Used to strip test-only overrides from agent processes.
130→func filterEnv(env []string, names ...string) []string {
131→	out := make([]string, 0, len(env))
132→	for _, e := range env {
133→		skip := false
134→		for _, name := range names {
135→			if strings.HasPrefix(e, name+"=") {
136→				skip = true
137→				break
138→			}
139→		}
140→		if !skip {
141→			out = append(out, e)
142→		}
143→	}
144→	return out
145→}
