 32→func (k *Kiro) IsTransientError(out Output, _ error) bool {
 33→	combined := out.Stdout + out.Stderr
 34→	transientPatterns := []string{
 35→		"overloaded",
 36→		"rate limit",
 37→		"529",
 38→		"503",
 39→		"500",
 40→		"ECONNRESET",
 41→		"ETIMEDOUT",
 42→	}
 43→	for _, p := range transientPatterns {
 44→		if strings.Contains(combined, p) {
 45→			return true
 46→		}
 47→	}
 48→	return false
 49→}
