104→func (k *Kiro) StartSession(ctx context.Context, dir string) (Session, error) {
105→	name := fmt.Sprintf("kiro-test-%d", time.Now().UnixNano())
106→
107→	s, err := NewTmuxSession(name, dir, []string{"ENTIRE_TEST_TTY"}, k.Binary(), "chat", "--trust-all-tools", "--agent", "entire")
108→	if err != nil {
109→		return nil, err
110→	}
111→
112→	// Wait for the initial prompt to appear.
113→	if _, err := s.WaitFor(k.PromptPattern(), 30*time.Second); err != nil {
114→		_ = s.Close()
115→		return nil, fmt.Errorf("waiting for initial prompt: %w", err)
116→	}
117→	s.stableAtSend = ""
118→
119→	return s, nil
120→}
