228→// WaitFor waits for a pattern in the interactive session's pane and logs the
229→// pane content to ConsoleLog after the wait completes.
230→func (s *RepoState) WaitFor(t *testing.T, session agents.Session, pattern string, timeout time.Duration) {
231→	t.Helper()
232→	content, err := session.WaitFor(pattern, timeout)
233→	fmt.Fprintf(s.ConsoleLog, "> pane after WaitFor(%q):\n%s\n", pattern, content)
234→	if err != nil {
