279→// Git runs a git command in the given directory and fails the test on error.
280→func Git(t *testing.T, dir string, args ...string) {
281→	t.Helper()
282→
283→	cmd := exec.Command("git", args...)
284→	if dir != "" {
285→		cmd.Dir = dir
286→	}
287→	cmd.Env = append(os.Environ(), "ENTIRE_TEST_TTY=0")
288→
289→	out, err := cmd.CombinedOutput()
290→	if err != nil {
291→		t.Fatalf("git %s failed: %v\n%s", strings.Join(args, " "), err, out)
292→	}
293→}
