295→// GitOutput runs a git command in the given directory, returns its trimmed
296→// stdout, and fails the test on error.
297→func GitOutput(t *testing.T, dir string, args ...string) string {
298→	t.Helper()
299→
300→	cmd := exec.Command("git", args...)
301→	if dir != "" {
302→		cmd.Dir = dir
303→	}
304→
305→	out, err := cmd.Output()
306→	if err != nil {
307→		var stderr string
308→		ee := &exec.ExitError{}
309→		if errors.As(err, &ee) {
310→			stderr = string(ee.Stderr)
311→		}
312→		t.Fatalf("git %s failed: %v\n%s", strings.Join(args, " "), err, stderr)
313→	}
314→
315→	return strings.TrimSpace(string(out))
316→}
