330→// CheckpointIDs lists all checkpoint IDs from the tree at the tip of the
331→// checkpoint branch.
332→func CheckpointIDs(t *testing.T, dir string) []string {
333→	t.Helper()
334→	out := gitOutputSafe(dir, "ls-tree", "-r", "--name-only", "entire/checkpoints/v1")
335→	if out == "" {
336→		return nil
337→	}
338→	seen := map[string]bool{}
339→	var ids []string
340→	for _, line := range strings.Split(strings.TrimSpace(out), "\n") {
341→		parts := strings.Split(line, "/")
342→		if len(parts) == 3 && parts[2] == "metadata.json" {
343→			id := parts[0] + parts[1]
344→			if !seen[id] {
345→				seen[id] = true
346→				ids = append(ids, id)
347→			}
348→		}
349→	}
350→	return ids
351→}
