389→// SetupBareRemote creates a bare git repo, adds it as "origin", and pushes
390→// the initial commit. Returns the bare repo path.
391→func SetupBareRemote(t *testing.T, s *RepoState) string {
392→	t.Helper()
393→
394→	var bareDir string
395→	if os.Getenv("E2E_KEEP_REPOS") != "" {
396→		var err error
397→		bareDir, err = os.MkdirTemp("", "e2e-bare-*")
398→		if err != nil {
