 22→// NewTestEnv creates a bare test environment with ENTIRE_REPO_ROOT and isolated HOME.
 23→func NewTestEnv(t *testing.T, agentName string) *TestEnv {
 24→	t.Helper()
 25→
 26→	binPath, ok := AgentBinaries[agentName]
 27→	if !ok {
 28→		t.Fatalf("agent binary not found: %s (available: %v)", agentName, agentBinaryNames())
 29→	}
 30→
 31→	dir := t.TempDir()
 32→	homeDir := t.TempDir()
 33→
 34→	env := baseEnv(dir, homeDir)
 35→
 36→	return &TestEnv{
 37→		t:       t,
 38→		Dir:     dir,
 39→		HomeDir: homeDir,
 40→		Runner: &AgentRunner{
 41→			BinaryPath: binPath,
 42→			Env:        env,
 43→		},
 44→	}
 45→}
 46→
 47→// NewTestEnvWithBinary creates a test environment using an explicit binary path.
 48→// Use this from subpackages that build their own agent binary in TestMain.
 49→func NewTestEnvWithBinary(t *testing.T, binPath string) *TestEnv {
 50→	t.Helper()
 51→
 52→	dir := t.TempDir()
 53→	homeDir := t.TempDir()
 54→
 55→	env := baseEnv(dir, homeDir)
 56→
 57→	return &TestEnv{
 58→		t:       t,
 59→		Dir:     dir,
 60→		HomeDir: homeDir,
 61→		Runner: &AgentRunner{
 62→			BinaryPath: binPath,
 63→			Env:        env,
 64→		},
 65→	}
 66→}
 67→
 68→// WriteFile writes content to a path relative to the test environment root.
 69→func (e *TestEnv) WriteFile(relPath, content string) {
 70→	e.t.Helper()
 71→	abs := filepath.Join(e.Dir, relPath)
 72→	if err := os.MkdirAll(filepath.Dir(abs), 0o750); err != nil {
 73→		e.t.Fatalf("mkdir for %s: %v", relPath, err)
 74→	}
 75→	if err := os.WriteFile(abs, []byte(content), 0o600); err != nil {
 76→		e.t.Fatalf("write %s: %v", relPath, err)
 77→	}
 78→}
 79→
 80→// WriteJSON writes a JSON-encoded value to a path relative to the test root.
 81→func (e *TestEnv) WriteJSON(relPath string, v any) {
 82→	e.t.Helper()
 83→	data, err := json.Marshal(v)
 84→	if err != nil {
 85→		e.t.Fatalf("marshal JSON for %s: %v", relPath, err)
 86→	}
 87→	e.WriteFile(relPath, string(data))
 88→}
 89→
 90→// ReadFile reads a file relative to the test environment root.
 91→func (e *TestEnv) ReadFile(relPath string) string {
 92→	e.t.Helper()
 93→	data, err := os.ReadFile(filepath.Join(e.Dir, relPath))
 94→	if err != nil {
 95→		e.t.Fatalf("read %s: %v", relPath, err)
 96→	}
 97→	return string(data)
 98→}
 99→
100→// FileExists checks whether a relative path exists in the test environment.
101→func (e *TestEnv) FileExists(relPath string) bool {
102→	_, err := os.Stat(filepath.Join(e.Dir, relPath))
103→	return err == nil
104→}
105→
106→// MkdirAll creates a directory (and parents) relative to the test root.
107→func (e *TestEnv) MkdirAll(relPath string) {
108→	e.t.Helper()
109→	if err := os.MkdirAll(filepath.Join(e.Dir, relPath), 0o750); err != nil {
110→		e.t.Fatalf("mkdir %s: %v", relPath, err)
111→	}
112→}
113→
114→// GitInit initializes a git repo in the test environment root.
115→func (e *TestEnv) GitInit() {
116→	e.t.Helper()
117→	cmd := exec.Command("git", "init")
118→	cmd.Dir = e.Dir
119→	cmd.Env = e.Runner.Env
120→	if out, err := cmd.CombinedOutput(); err != nil {
121→		e.t.Fatalf("git init failed: %v\n%s", err, out)
122→	}
123→}
124→
125→// AbsPath returns the absolute path for a relative path in the test environment.
126→func (e *TestEnv) AbsPath(relPath string) string {
127→	return filepath.Join(e.Dir, relPath)
128→}
129→
130→func baseEnv(repoRoot, homeDir string) []string {
131→	return []string{
132→		fmt.Sprintf("ENTIRE_REPO_ROOT=%s", repoRoot),
133→		fmt.Sprintf("HOME=%s", homeDir),
134→		fmt.Sprintf("PATH=%s", os.Getenv("PATH")),
135→		"LANG=en_US.UTF-8",
136→	}
137→}
138→
139→func agentBinaryNames() []string {
140→	names := make([]string, 0, len(AgentBinaries))
141→	for name := range AgentBinaries {
142→		names = append(names, name)
143→	}
144→	return names
145→}
