161→func mergeDroidCustomModels(globalSettingsPath, repoSettingsPath string) error {
162→	globalSettings, err := loadJSONMap(globalSettingsPath, "global droid settings")
163→	if err != nil {
164→		return err
165→	}
166→
167→	customModels, ok := globalSettings["customModels"]
168→	if !ok {
169→		return fmt.Errorf(
170→			"global droid settings at %s missing customModels; repo-local %s shadows global settings",
171→			globalSettingsPath,
172→			repoSettingsPath,
173→		)
174→	}
175→
176→	var models []json.RawMessage
177→	if err := json.Unmarshal(customModels, &models); err != nil {
178→		return fmt.Errorf("parse customModels in %s: %w", globalSettingsPath, err)
179→	}
180→	if len(models) == 0 {
181→		return fmt.Errorf("global droid settings at %s has empty customModels", globalSettingsPath)
182→	}
183→
184→	repoSettings, err := loadJSONMap(repoSettingsPath, "repo-local droid settings")
185→	if err != nil {
186→		return err
187→	}
188→	repoSettings["customModels"] = customModels
189→
190→	// Set the active custom model so interactive mode uses the BYOK model
191→	// instead of prompting for selection. The value must match the Model
192→	// field from the customModels entry (not the displayName).
193→	modelJSON, err := json.Marshal(agents.DefaultDroidModel())
194→	if err != nil {
195→		return fmt.Errorf("marshal model setting: %w", err)
196→	}
197→	repoSettings["model"] = json.RawMessage(modelJSON)
198→
199→	// High autonomy prevents Droid from asking for confirmation during
200→	// interactive E2E tests, which would cause hangs waiting for input.
201→	repoSettings["autonomyMode"] = json.RawMessage(`"auto-high"`)
202→	repoSettings["completionSound"] = json.RawMessage(`"off"`)
203→
204→	out, err := json.MarshalIndent(repoSettings, "", "  ")
205→	if err != nil {
206→		return fmt.Errorf("marshal repo-local droid settings: %w", err)
207→	}
208→	out = append(out, '\n')
209→
210→	if err := os.WriteFile(repoSettingsPath, out, 0o600); err != nil {
211→		return fmt.Errorf("write repo-local droid settings %s: %w", repoSettingsPath, err)
212→	}
213→	return nil
214→}
