266→// ForEachAgent runs fn as a parallel subtest for every registered agent.
267→// It handles repo setup, concurrency gating, context timeout, and cleanup.
268→// The timeout is scaled by each agent's TimeoutMultiplier.
269→//
270→// If RunPrompt detects a transient API error (e.g. rate limit, token refresh
271→// failure), it panics with errScenarioRestart. ForEachAgent recovers from the
272→// panic and restarts the entire scenario with a fresh repository, up to
273→// maxScenarioRestarts times. This avoids stale CLI session state from the
274→// failed attempt poisoning the retry.
275→func ForEachAgent(t *testing.T, timeout time.Duration, fn func(t *testing.T, s *RepoState, ctx context.Context)) {
276→	t.Helper()
277→	t.Parallel()
278→	all := agents.All()
279→	if len(all) == 0 {
280→		t.Skip("no agents registered (check E2E_AGENT filter)")
281→	}
282→	for _, agent := range all {
283→		t.Run(agent.Name(), func(t *testing.T) {
284→			// Use the global test deadline for slot wait so we don't
285→			// skip prematurely — only bail if the whole binary is dying.
286→			slotCtx := context.Background()
287→			if deadline, ok := t.Deadline(); ok {
288→				var cancel context.CancelFunc
289→				slotCtx, cancel = context.WithDeadline(slotCtx, deadline)
290→				defer cancel()
291→			}
292→			if err := agents.AcquireSlot(slotCtx, agent); err != nil {
293→				t.Fatalf("timed out waiting for agent slot: %v", err)
294→			}
295→			defer agents.ReleaseSlot(agent)
296→
297→			// Per-test timeout starts after slot is acquired, scaled
298→			// by the agent's multiplier (e.g. 2.5× for gemini).
299→			scaled := time.Duration(float64(timeout) * agent.TimeoutMultiplier())
300→
301→			var prevState *RepoState
302→			for attempt := range maxScenarioRestarts + 1 {
303→				s := SetupRepo(t, agent)
304→				ctx, cancel := context.WithTimeout(context.Background(), scaled)
305→
306→				// On restart, suppress artifact capture from the previous
307→				// failed attempt so it doesn't overwrite the final one.
308→				if prevState != nil {
309→					prevState.skipArtifacts = true
310→				}
311→
312→				restarted := runScenario(t, s, ctx, fn)
313→				cancel()
314→
315→				if !restarted {
316→					return
317→				}
318→				prevState = s
319→				if attempt >= maxScenarioRestarts {
320→					t.Fatalf("exhausted %d scenario attempts due to transient API errors", maxScenarioRestarts+1)
321→				}
322→				t.Logf("transient error, restarting scenario (attempt %d/%d)", attempt+2, maxScenarioRestarts+1)
323→			}
324→		})
325→	}
326→}
