 11→// BinPath returns the path to the entire binary.
 12→// It checks E2E_ENTIRE_BIN first, then falls back to looking in PATH.
 13→func BinPath() string {
 14→	if p := os.Getenv("E2E_ENTIRE_BIN"); p != "" {
 15→		return p
 16→	}
 17→	if p, err := exec.LookPath("entire"); err == nil {
 18→		return p
 19→	}
 20→	return "entire"
 21→}
 22→
 23→// RewindPoint represents a single entry from `entire rewind --list`.
 24→type RewindPoint struct {
 25→	ID             string `json:"id"`
 26→	Message        string `json:"message"`
 27→	MetadataDir    string `json:"metadata_dir"`
 28→	Date           string `json:"date"`
 29→	IsLogsOnly     bool   `json:"is_logs_only"`
 30→	CondensationID string `json:"condensation_id"`
 31→	SessionID      string `json:"session_id"`
 32→}
 33→
 34→// Enable runs `entire enable` for the given agent with telemetry disabled.
 35→func Enable(t *testing.T, dir, agent string) {
 36→	t.Helper()
 37→	run(t, dir, "enable", "--agent", agent, "--telemetry=false")
 38→}
 39→
 40→// Disable runs `entire disable` in the given directory.
 41→func Disable(t *testing.T, dir string) {
 42→	t.Helper()
 43→	run(t, dir, "disable")
 44→}
 45→
 46→// RewindList runs `entire rewind --list` and parses the JSON output.
 47→func RewindList(t *testing.T, dir string) []RewindPoint {
 48→	t.Helper()
 49→	out := run(t, dir, "rewind", "--list")
 50→
 51→	var points []RewindPoint
 52→	if err := json.Unmarshal([]byte(out), &points); err != nil {
 53→		t.Fatalf("parse rewind list: %v\nraw output: %s", err, out)
 54→	}
 55→	return points
 56→}
 57→
 58→// Rewind runs `entire rewind --to <id>`. Returns an error instead of
 59→// failing the test, since callers may test failure cases.
 60→func Rewind(t *testing.T, dir, id string) error {
 61→	t.Helper()
 62→	return runErr(dir, "rewind", "--to", id)
 63→}
 64→
 65→// RewindLogsOnly runs `entire rewind --to <id> --logs-only`.
 66→func RewindLogsOnly(t *testing.T, dir, id string) error {
 67→	t.Helper()
 68→	return runErr(dir, "rewind", "--to", id, "--logs-only")
 69→}
 70→
 71→// run executes an `entire` subcommand in dir and fails the test on error.
 72→func run(t *testing.T, dir string, args ...string) string {
 73→	t.Helper()
 74→	cmd := exec.Command(BinPath(), args...)
 75→	cmd.Dir = dir
 76→	cmd.Env = append(os.Environ(), "ENTIRE_TEST_TTY=0")
 77→
 78→	out, err := cmd.CombinedOutput()
 79→	if err != nil {
 80→		t.Fatalf("entire %s failed: %v\n%s", strings.Join(args, " "), err, out)
 81→	}
 82→	return strings.TrimSpace(string(out))
 83→}
 84→
 85→// runErr executes an `entire` subcommand in dir and returns any error.
 86→func runErr(dir string, args ...string) error {
 87→	cmd := exec.Command(BinPath(), args...)
 88→	cmd.Dir = dir
 89→	cmd.Env = append(os.Environ(), "ENTIRE_TEST_TTY=0")
 90→
 91→	out, err := cmd.CombinedOutput()
 92→	if err != nil {
 93→		return &ExecError{
 94→			Args:   args,
 95→			Err:    err,
 96→			Output: string(out),
 97→		}
 98→	}
 99→	return nil
100→}
101→
102→// ExecError wraps an entire CLI execution failure with its output.
103→type ExecError struct {
104→	Args   []string
105→	Err    error
106→	Output string
107→}
108→
109→func (e *ExecError) Error() string {
110→	return "entire " + strings.Join(e.Args, " ") + ": " + e.Err.Error() + "\n" + e.Output
111→}
112→
113→func (e *ExecError) Unwrap() error {
114→	return e.Err
115→}
