175→// RunPrompt runs an agent prompt, logs the command and output to ConsoleLog,
176→// and returns the result. If the agent reports a transient API error, it
177→// panics with errScenarioRestart to trigger a full scenario restart.
178→func (s *RepoState) RunPrompt(t *testing.T, ctx context.Context, prompt string, opts ...agents.Option) (agents.Output, error) {
179→	t.Helper()
180→	out, err := s.Agent.RunPrompt(ctx, s.Dir, prompt, opts...)
181→	s.logPromptResult(out)
182→
183→	if err != nil && s.Agent.IsTransientError(out, err) {
184→		errMsg := fmt.Sprintf("transient API error (stderr: %s)", strings.TrimSpace(out.Stderr))
185→		t.Logf("%s — restarting scenario", errMsg)
186→		fmt.Fprintf(s.ConsoleLog, "> [transient] %s — restarting scenario\n", errMsg)
187→		panic(errScenarioRestart{msg: errMsg})
188→	}
189→
190→	return out, err
191→}
